// src/app.js
const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

// src/modules/projects/routes.js
const express = require('express');
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/:projectId', async (req, res) => {
  try {
    const project = await projectsService.getProjectById(req.params.projectId);
    if (!project) {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    }
    res.json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  try {
    const { name } = req.body;
    if (!name || typeof name !== 'string' || name.trim() === '') {
      return sendError(res, 400, 'INVALID_NAME', 'Invalid project name');
    }
    const newProject = await projectsService.createProject(name);
    res.status(201).json({ project: newProject });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/members/routes.js
const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    const members = await membersService.getAllMembers(projectId);
    res.json({ members });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    const { userId, role } = req.body;
    if (!userId || typeof userId !== 'string' || !role || typeof role !== 'string') {
      return sendError(res, 400, 'INVALID_INPUT', 'Invalid input');
    }
    const newMember = await membersService.addMember(projectId, userId, role);
    if (!newMember) {
      return sendError(res, 409, 'MEMBER_ALREADY_EXISTS', 'Member already exists');
    }
    res.status(201).json({ member: newMember });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/tasks/routes.js
const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    const status = req.query.status;
    let tasks = await tasksService.getAllTasks(projectId);
    if (status === 'todo' || status === 'done') {
      tasks = tasks.filter(task => task.status === 'done');
    }
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    const { description } = req.body;
    if (!description || typeof description !== 'string' || description.trim() === '') {
      return sendError(res, 400, 'INVALID_DESCRIPTION', 'Invalid task description');
    }
    const newTask = await tasksService.createTask(projectId, description);
    res.status(201).json({ task: newTask });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.patch('/:taskId', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    const taskId = req.params.taskId;
    const { status } = req.body;
    if (!status || (status !== 'todo' && status !== 'done')) {
      return sendError(res, 400, 'INVALID_STATUS', 'Invalid task status');
    }
    const updatedTask = await tasksService.updateTaskStatus(projectId, taskId, status);
    if (!updatedTask) {
      return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
    }
    res.json({ task: updatedTask });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/comments/routes.js
const express = require('express');
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    const taskId = req.params.taskId;
    const comments = await commentsService.getAllComments(projectId, taskId);
    res.json({ comments });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    const taskId = req.params.taskId;
    const { message } = req.body;
    if (!message || typeof message !== 'string' || message.trim() === '') {
      return sendError(res, 400, 'INVALID_MESSAGE', 'Invalid comment message');
    }
    const newComment = await commentsService.addComment(projectId, taskId, message);
    res.status(201).json({ comment: newComment });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/lib/errors.js
const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

module.exports = { sendError };

